import type { Link } from "../../componentTypes/link"
import type { Semantics } from "../semantics"

const link = (semantics: Semantics): Link => ({
  textColor: semantics.color.institutional.linkColor,
  textHoverColor: semantics.color.text.interactive.navigation.primary.hover,
  textDisabledColor: semantics.color.text.interactive.disabled.base,
  onColorTextColor: semantics.color.text.interactive.navigation.primaryOnColor.base,
  onColorTextHoverColor: semantics.color.text.interactive.navigation.primaryOnColor.hover,
  onColorTextDisabledColor: semantics.color.text.interactive.disabled.onColor,
  fontSizeSm: semantics.fontSize.textSm,
  fontSizeMd: semantics.fontSize.textBase,
  fontSizeLg: "22px",
  fontWeight: semantics.fontWeight.interactive,
  gapSm: semantics.spacing.space2xs,
  gapMd: semantics.spacing.spaceXs,
  gapLg: semantics.spacing.spaceXs,
  lineHeightSm: semantics.lineHeight.standalone.textSm,
  lineHeightMd: semantics.lineHeight.standalone.textBase,
  lineHeightLg: "33px",
  fontFamily: semantics.fontFamily.base,
  inlineLink: {
    small: {
      fontFamily: semantics.fontFamily.base,
      fontWeight: semantics.fontWeight.body.base,
      fontSize: semantics.fontSize.textSm,
      lineHeight: semantics.lineHeight.paragraph.textSm,
      textDecoration: "underline",
    },
    medium: {
      fontFamily: semantics.fontFamily.base,
      fontWeight: semantics.fontWeight.body.base,
      fontSize: semantics.fontSize.textBase,
      lineHeight: semantics.lineHeight.paragraph.textBase,
      textDecoration: "underline",
    },
    large: {
      fontFamily: semantics.fontFamily.base,
      fontWeight: semantics.fontWeight.body.base,
      fontSize: "22px",
      lineHeight: "33px",
      textDecoration: "underline",
    },
  },
  textDecorationWithinText: "underline",
  textDecorationOutsideText: "none",
  unstyledTextColor: semantics.color.text.base,
})
export default link
